(function(){const DOCSEARCH_CONTAINER_SELECTOR='#docsearch';const DOCSEARCH_MODAL_SELECTOR='.DocSearch-Container';const DOCSEARCH_POLL_INTERVAL=100;const DOCSEARCH_MAX_WAIT_COUNT=100;const CONTAINER_RETRY_DELAY=100;const CONTAINER_MAX_RETRY_COUNT=20;const MATERIAL_OBSERVER_POLL_INTERVAL=100;const MATERIAL_OBSERVER_MAX_WAIT_COUNT=100;const DOM_OBSERVER_DEBOUNCE=80;let currentContainer=null;let currentInstance=null;let libraryPromise=null;let initSequence=0;let containerRetryTimer=null;let pageChangeSubscribed=false;let observerWaitTimer=null;let domObserver=null;let mountScheduleTimer=null;function waitForDocSearchLibrary(){if(typeof window.docsearch!=='undefined'){return Promise.resolve(window.docsearch);}
if(libraryPromise){return libraryPromise;}
libraryPromise=new Promise((resolve,reject)=>{let waitCount=0;const timer=window.setInterval(()=>{if(typeof window.docsearch!=='undefined'){window.clearInterval(timer);resolve(window.docsearch);return;}
waitCount+=1;if(waitCount>=DOCSEARCH_MAX_WAIT_COUNT){window.clearInterval(timer);reject(new Error('DocSearch library not loaded'));}},DOCSEARCH_POLL_INTERVAL);}).finally(()=>{libraryPromise=null;});return libraryPromise;}
function removeStaleDocSearchModals(){document.querySelectorAll(DOCSEARCH_MODAL_SELECTOR).forEach((modal)=>{modal.remove();});document.body.classList.remove('DocSearch--active');}
function resetCurrentContainer(){if(currentContainer){currentContainer.textContent='';delete currentContainer.dataset.docsearchInitialized;}}
function destroyCurrentInstance(){if(currentInstance&&typeof currentInstance.destroy==='function'){currentInstance.destroy();}
currentInstance=null;resetCurrentContainer();removeStaleDocSearchModals();}
function clearContainerRetryTimer(){if(containerRetryTimer!==null){window.clearTimeout(containerRetryTimer);containerRetryTimer=null;}}
function scheduleRetry(retryCount){clearContainerRetryTimer();containerRetryTimer=window.setTimeout(()=>{void mountDocSearch(retryCount+1);},CONTAINER_RETRY_DELAY);}
function afterNextPaint(callback){window.requestAnimationFrame(()=>{window.requestAnimationFrame(callback);});}
function clearMountScheduleTimer(){if(mountScheduleTimer!==null){window.clearTimeout(mountScheduleTimer);mountScheduleTimer=null;}}
function scheduleMountDocSearch(){clearMountScheduleTimer();mountScheduleTimer=window.setTimeout(()=>{mountScheduleTimer=null;afterNextPaint(()=>{void mountDocSearch();});},DOM_OBSERVER_DEBOUNCE);}
function shouldAttemptMount(){const container=document.querySelector(DOCSEARCH_CONTAINER_SELECTOR);if(!container){return currentContainer!==null||currentInstance!==null;}
return(container!==currentContainer||container.dataset.docsearchInitialized!=='true'||container.childElementCount===0);}
async function mountDocSearch(retryCount=0){if(currentContainer&&!currentContainer.isConnected){currentContainer=null;currentInstance=null;}
const container=document.querySelector(DOCSEARCH_CONTAINER_SELECTOR);if(!container){if(retryCount<CONTAINER_MAX_RETRY_COUNT){scheduleRetry(retryCount);return;}
clearContainerRetryTimer();destroyCurrentInstance();currentContainer=null;return;}
clearContainerRetryTimer();if(container===currentContainer&&container.dataset.docsearchInitialized==='true'){return;}
const currentSequence=++initSequence;if(container!==currentContainer){destroyCurrentInstance();currentContainer=container;}
try{const createDocSearch=await waitForDocSearchLibrary();if(currentSequence!==initSequence||currentContainer!==container){return;}
container.textContent='';const instance=createDocSearch({appId:'SDEU4ZQ2OW',apiKey:'57fa46cd9411b8431d55daeb5ae52b77',indexName:'柯懒不是柯南',container,placeholder:'搜索文档...',translations:{button:{buttonText:'搜索',buttonAriaLabel:'搜索'},modal:{searchBox:{resetButtonTitle:'清除查询条件',resetButtonAriaLabel:'清除查询条件',cancelButtonText:'取消',cancelButtonAriaLabel:'取消'},startScreen:{recentSearchesTitle:'搜索历史',noRecentSearchesText:'没有搜索历史',saveRecentSearchButtonTitle:'保存至搜索历史',removeRecentSearchButtonTitle:'从搜索历史中移除',favoriteSearchesTitle:'收藏',removeFavoriteSearchButtonTitle:'从收藏中移除'},errorScreen:{titleText:'无法获取结果',helpText:'你可能需要检查你的网络连接'},footer:{selectText:'选择',selectKeyAriaLabel:'回车键',navigateText:'切换',navigateUpKeyAriaLabel:'向上箭头',navigateDownKeyAriaLabel:'向下箭头',closeText:'关闭',closeKeyAriaLabel:'Escape键',searchByText:'搜索提供'},noResultsScreen:{noResultsText:'无法找到相关结果',suggestedQueryText:'你可以尝试查询',reportMissingResultsText:'你认为这个查询应该有结果？',reportMissingResultsLinkText:'点击反馈'}}},debug:false});if(currentSequence!==initSequence||currentContainer!==container){if(instance&&typeof instance.destroy==='function'){instance.destroy();}
return;}
currentInstance=instance;container.dataset.docsearchInitialized='true';console.log('DocSearch initialized successfully');}catch(error){if(currentSequence!==initSequence){return;}
console.error('Error initializing DocSearch:',error);}}
function clearObserverWaitTimer(){if(observerWaitTimer!==null){window.clearInterval(observerWaitTimer);observerWaitTimer=null;}}
function trySubscribeToMaterialDocument(callback){if(pageChangeSubscribed){return true;}
if(typeof document$==='undefined'||typeof document$.subscribe!=='function'){return false;}
document$.subscribe(()=>{callback();});pageChangeSubscribed=true;clearObserverWaitTimer();return true;}
function subscribeToPageChanges(callback){const runNow=()=>{afterNextPaint(()=>{callback();});};if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',runNow,{once:true});}else{runNow();}
if(trySubscribeToMaterialDocument(callback)){return;}
let waitCount=0;clearObserverWaitTimer();observerWaitTimer=window.setInterval(()=>{waitCount+=1;if(trySubscribeToMaterialDocument(callback)){return;}
if(waitCount>=MATERIAL_OBSERVER_MAX_WAIT_COUNT){clearObserverWaitTimer();}},MATERIAL_OBSERVER_POLL_INTERVAL);}
function observeDomChanges(){if(domObserver||typeof MutationObserver==='undefined'){return;}
domObserver=new MutationObserver(()=>{if(shouldAttemptMount()){scheduleMountDocSearch();}});domObserver.observe(document.documentElement,{childList:true,subtree:true});}
subscribeToPageChanges(()=>{scheduleMountDocSearch();observeDomChanges();});})();